package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.dto.Requests.*; import co.edu.elecciones.dto.Responses.*; import co.edu.elecciones.repository.*; import co.edu.elecciones.service.PredictionService; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/mcp") public class McpController { private final OfficialResultRepository results; private final PollRepository polls; private final CandidateRepository candidates; private final PartyRepository parties; private final PredictionService predictions; public McpController(OfficialResultRepository r,PollRepository p,CandidateRepository c,PartyRepository pa,PredictionService pr){results=r;polls=p;candidates=c;parties=pa;predictions=pr;} @GetMapping("/tools") public ApiResponse<List<Tool>> tools(){ return ApiResponse.ok("Herramientas MCP autorizadas",List.of(new Tool("consultar_resultados","Consulta resultados persistidos",List.of("PUBLIC","ANALISTA","ADMINISTRADOR")),new Tool("consultar_encuestas","Consulta encuestas registradas",List.of("ANALISTA","ADMINISTRADOR")),new Tool("consultar_candidatos_partidos","Consulta candidatos y partidos",List.of("PUBLIC","ANALISTA","ADMINISTRADOR")),new Tool("generar_resumen","Resumen explicable sin SQL libre",List.of("PUBLIC","ANALISTA","ADMINISTRADOR")))); } @PostMapping("/invoke") public ApiResponse<Object> invoke(@RequestBody McpInvokeRequest req){ return switch(req.tool()){ case "consultar_resultados" -> ApiResponse.ok("OK",results.findAll()); case "consultar_encuestas" -> ApiResponse.ok("OK",polls.findAll()); case "consultar_candidatos_partidos" -> ApiResponse.ok("OK",Map.of("candidatos",candidates.findAll(),"partidos",parties.findAll())); case "generar_resumen" -> ApiResponse.ok("OK",predictions.byPartialResults()); default -> ApiResponse.error("Tool MCP no autorizada"); }; }}
